import java.util.HashMap;
import java.util.Map;

public class SmartHomeSystem {
    // Constants for configuration and default values
    private static final int DEFAULT_BRIGHTNESS = 50;
    private static final int MIN_BRIGHTNESS = 0;
    private static final int MAX_BRIGHTNESS = 100;
    private static final String[] VALID_ROOMS = {"Living Room", "Kitchen", "Bedroom", "Bathroom"};

    // Data structures to store light status and command history
    private Map<String, Boolean> lightStatus;
    private Map<String, Integer> brightnessLevels;
    private Map<String, String> commandHistory;

    public SmartHomeSystem() {
        lightStatus = new HashMap<>();
        brightnessLevels = new HashMap<>();
        commandHistory = new HashMap<>();

        // Initialize default values for all rooms
        for (String room : VALID_ROOMS) {
            lightStatus.put(room, false);
            brightnessLevels.put(room, DEFAULT_BRIGHTNESS);
            commandHistory.put(room, "Initialized with lights off and brightness " + DEFAULT_BRIGHTNESS);
        }
    }

    public void turnOn(String room) {
        if (!isValidRoom(room)) {
            System.out.println("Error: Invalid room '" + room + "'");
            return;
        }

        lightStatus.put(room, true);
        commandHistory.put(room, "Lights turned on");
        System.out.println("Lights in " + room + " are now ON");
    }

    public void turnOff(String room) {
        if (!isValidRoom(room)) {
            System.out.println("Error: Invalid room '" + room + "'");
            return;
        }

        lightStatus.put(room, false);
        commandHistory.put(room, "Lights turned off");
        System.out.println("Lights in " + room + " are now OFF");
    }

    public void adjustBrightness(String room, int level) {
        if (!isValidRoom(room)) {
            System.out.println("Error: Invalid room '" + room + "'");
            return;
        }

        if (level < MIN_BRIGHTNESS || level > MAX_BRIGHTNESS) {
            System.out.println("Error: Brightness must be between " + MIN_BRIGHTNESS + " and " + MAX_BRIGHTNESS);
            return;
        }

        brightnessLevels.put(room, level);
        commandHistory.put(room, "Brightness adjusted to " + level);
        System.out.println("Brightness in " + room + " set to " + level);
    }

    public String checkStatus(String room) {
        if (!isValidRoom(room)) {
            return "Error: Invalid room '" + room + "'";
        }

        String status = lightStatus.get(room) ? "ON" : "OFF";
        int brightness = brightnessLevels.get(room);
        return "Room: " + room + ", Status: " + status + ", Brightness: " + brightness;
    }

    private boolean isValidRoom(String room) {
        for (String validRoom : VALID_ROOMS) {
            if (validRoom.equals(room)) {
                return true;
            }
        }
        return false;
    }
}
