class HardwareStore {
public:
    void ADD(const std::string& item_name, int quantity, double price) {
        inventory[item_name] = {quantity, price};
    }

    void REMOVE(const std::string& item_name) {
        auto it = inventory.find(item_name);
        if (it != inventory.end()) {
            inventory.erase(it);
        } else {
            std::cout << "Error: Item '" << item_name << "' not found." << std::endl;
        }
    }

    void UPDATE(const std::string& item_name, int new_quantity, double new_price) {
        auto it = inventory.find(item_name);
        if (it != inventory.end()) {
            it->second.quantity = new_quantity;
            it->second.price = new_price;
        } else {
            std::cout << "Error: Item '" << item_name << "' not found." << std::endl;
        }
    }

    void DISPLAY() const {
        std::cout << std::left << std::setw(20) << "Item Name" 
                  << std::setw(10) << "Quantity" 
                  << std::setw(10) << "Price" << std::endl;
        std::cout << std::string(40, '-') << std::endl;
        for (const auto& item : inventory) {
            std::cout << std::left << std::setw(20) << item.first 
                      << std::setw(10) << item.second.quantity 
                      << std::setw(10) << item.second.price << std::endl;
        }
    }

protected:
    // No protected members for this implementation

private:
    struct Item {
        int quantity = 0;
        double price = 0.0;
    };
    std::map<std::string, Item> inventory;
};

int main() {
    HardwareStore store;
    std::string command;

    while (true) {
        std::cout << "Enter command (ADD, REMOVE, UPDATE, DISPLAY, EXIT): ";
        std::cin >> command;

        if (command == "ADD") {
            std::string item_name;
            int quantity;
            double price;
            std::cin >> item_name >> quantity >> price;
            store.ADD(item_name, quantity, price);
        } else if (command == "REMOVE") {
            std::string item_name;
            std::cin >> item_name;
            store.REMOVE(item_name);
        } else if (command == "UPDATE") {
            std::string item_name;
            int new_quantity;
            double new_price;
            std::cin >> item_name >> new_quantity >> new_price;
            store.UPDATE(item_name, new_quantity, new_price);
        } else if (command == "DISPLAY") {
            store.DISPLAY();
        } else if (command == "EXIT") {
            break;
        } else {
            std::cout << "Invalid command." << std::endl;
        }
    }

    return 0;
}
