function processChartData(dataPoints) {
    const hourlyBuckets = {};
    let currentHour;
    let hourKey;
    let sum;
    let count;
    let averageValue;
    let hourDataPoints;

    for (let i = 0; i < dataPoints.length; i++) {
        const dataPoint = dataPoints[i];
        const date = new Date(dataPoint.timestamp);
        currentHour = date.getHours();
        hourKey = currentHour.toString();

        if (!hourlyBuckets[hourKey]) {
            hourlyBuckets[hourKey] = [];
        }

        hourlyBuckets[hourKey].push(dataPoint.value);
    }

    const result = {};

    for (const hour in hourlyBuckets) {
        hourDataPoints = hourlyBuckets[hour];
        sum = 0;
        count = hourDataPoints.length;

        for (let j = 0; j < hourDataPoints.length; j++) {
            sum += hourDataPoints[j];
        }

        averageValue = sum / count;
        result[hour] = averageValue;
    }

    return result;
}
