projects = {}

def ADD_PROJECT(project_name):
    if project_name in projects:
        print(f"Error: Project '{project_name}' already exists.")
    else:
        projects[project_name] = {'start_times': [], 'stop_times': []}

def START_TIME(project_name, time):
    if project_name not in projects:
        print(f"Error: Project '{project_name}' does not exist.")
    else:
        try:
            hours, minutes = map(int, time.split(':'))
            if hours < 0 or hours > 23 or minutes < 0 or minutes > 59:
                print(f"Error: Invalid time format '{time}'. Use HH:MM in 24-hour format.")
            else:
                projects[project_name]['start_times'].append((hours, minutes))
        except ValueError:
            print(f"Error: Invalid time format '{time}'. Use HH:MM in 24-hour format.")

def STOP_TIME(project_name, time):
    if project_name not in projects:
        print(f"Error: Project '{project_name}' does not exist.")
    else:
        try:
            hours, minutes = map(int, time.split(':'))
            if hours < 0 or hours > 23 or minutes < 0 or minutes > 59:
                print(f"Error: Invalid time format '{time}'. Use HH:MM in 24-hour format.")
            else:
                projects[project_name]['stop_times'].append((hours, minutes))
        except ValueError:
            print(f"Error: Invalid time format '{time}'. Use HH:MM in 24-hour format.")

def REPORT(project_name):
    if project_name not in projects:
        print(f"Error: Project '{project_name}' does not exist.")
    else:
        start_times = projects[project_name]['start_times']
        stop_times = projects[project_name]['stop_times']
        if len(start_times) != len(stop_times):
            print(f"Error: Mismatched start and stop times for project '{project_name}'.")
        else:
            total_minutes = 0
            for start, stop in zip(start_times, stop_times):
                start_h, start_m = start
                stop_h, stop_m = stop
                start_total = start_h * 60 + start_m
                stop_total = stop_h * 60 + stop_m
                if stop_total < start_total:
                    print(f"Error: Stop time before start time for project '{project_name}'.")
                    return
                total_minutes += (stop_total - start_total)
            hours = total_minutes // 60
            minutes = total_minutes % 60
            print(f"Total time spent on project '{project_name}': {hours} hours and {minutes} minutes.")

def main():
    while True:
        command = input("Enter command (ADD_PROJECT, START_TIME, STOP_TIME, REPORT, or EXIT): ").strip().split()
        if not command:
            continue
        cmd = command[0].upper()
        if cmd == 'EXIT':
            break
        elif cmd == 'ADD_PROJECT' and len(command) == 2:
            ADD_PROJECT(command[1])
        elif cmd == 'START_TIME' and len(command) == 3:
            START_TIME(command[1], command[2])
        elif cmd == 'STOP_TIME' and len(command) == 3:
            STOP_TIME(command[1], command[2])
        elif cmd == 'REPORT' and len(command) == 2:
            REPORT(command[1])
        else:
            print("Error: Invalid command or arguments.")

if __name__ == "__main__":
    main()
