function manageTemperatureRecords() {
    const records = {};

    function addRecord(location, temperature) {
        if (!records[location]) {
            records[location] = [];
        }
        const record = {
            date: new Date().toISOString(),
            temperature: temperature
        };
        records[location].push(record);
        return { success: true, message: 'Record added successfully.' };
    }

    function getAverage(location) {
        if (!records[location] || records[location].length === 0) {
            return { error: 'No records available for the specified location.' };
        }
        const temperatures = records[location].map(record => record.temperature);
        const sum = temperatures.reduce((acc, temp) => acc + temp, 0);
        const average = sum / temperatures.length;
        return { average: average };
    }

    function removeRecord(location, date) {
        if (!records[location]) {
            return { error: 'Location does not exist.' };
        }
        const initialLength = records[location].length;
        records[location] = records[location].filter(record => record.date !== date);
        if (records[location].length === initialLength) {
            return { error: 'No record found with the specified date.' };
        }
        return { success: true, message: 'Record removed successfully.' };
    }

    function updateRecord(location, date, newTemperature) {
        if (!records[location]) {
            return { error: 'Location does not exist.' };
        }
        const recordIndex = records[location].findIndex(record => record.date === date);
        if (recordIndex === -1) {
            return { error: 'No record found with the specified date.' };
        }
        records[location][recordIndex].temperature = newTemperature;
        return { success: true, message: 'Record updated successfully.' };
    }

    return {
        addRecord,
        getAverage,
        removeRecord,
        updateRecord
    };
}
