use std::collections::HashMap;
use std::error::Error;
use std::fmt;

#[derive(Debug)]
struct FileSystemError {
    message: String,
}

impl fmt::Display for FileSystemError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}", self.message)
    }
}

impl Error for FileSystemError {}

pub struct FileSystem {
    files: HashMap<String, String>,
}

impl FileSystem {
    pub fn new() -> Self {
        FileSystem {
            files: HashMap::new(),
        }
    }

    pub fn create_file(&mut self, path: &str, content: &str) -> Result<(), FileSystemError> {
        if self.files.contains_key(path) {
            return Err(FileSystemError {
                message: format!("File '{}' already exists", path),
            });
        }
        self.files.insert(path.to_string(), content.to_string());
        Ok(())
    }

    pub fn read_file(&self, path: &str) -> Result<String, FileSystemError> {
        match self.files.get(path) {
            Some(content) => Ok(content.clone()),
            None => Err(FileSystemError {
                message: format!("File '{}' does not exist", path),
            }),
        }
    }

    pub fn update_file(&mut self, path: &str, new_content: &str) -> Result<(), FileSystemError> {
        if !self.files.contains_key(path) {
            return Err(FileSystemError {
                message: format!("File '{}' does not exist", path),
            });
        }
        self.files.insert(path.to_string(), new_content.to_string());
        Ok(())
    }

    pub fn delete_file(&mut self, path: &str) -> Result<(), FileSystemError> {
        if !self.files.contains_key(path) {
            return Err(FileSystemError {
                message: format!("File '{}' does not exist", path),
            });
        }
        self.files.remove(path);
        Ok(())
    }

    // Protected function example (not directly accessible outside the module)
    #[allow(dead_code)]
    protected fn file_count(&self) -> usize {
        self.files.len()
    }

    // Private member (only accessible within the struct)
    // files: HashMap<String, String> is already private
}
