#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Process {
    char name[100];
    int priority;
    struct Process* next;
} Process;

Process* head = NULL;

void ADD(char* name, int priority);
void KILL(char* name);
void KILL_PRIORITY(int priority);
void LIST();
void freeProcesses();

int main() {
    char command[20];
    char name[100];
    int priority;
    int running;

    running = 1;

    while (running) {
        printf("> ");
        scanf("%s", command);

        if (strcmp(command, "ADD") == 0) {
            scanf("%s %d", name, &priority);
            ADD(name, priority);
        } else if (strcmp(command, "KILL") == 0) {
            scanf("%s", name);
            KILL(name);
        } else if (strcmp(command, "KILL_PRIORITY") == 0) {
            scanf("%d", &priority);
            KILL_PRIORITY(priority);
        } else if (strcmp(command, "LIST") == 0) {
            LIST();
        } else if (strcmp(command, "EXIT") == 0) {
            running = 0;
        } else {
            printf("Unknown command.\n");
        }
    }

    freeProcesses();
    return 0;
}

void ADD(char* name, int priority) {
    Process* newProcess;
    Process* current;
    Process* previous;

    newProcess = (Process*)malloc(sizeof(Process));
    strcpy(newProcess->name, name);
    newProcess->priority = priority;
    newProcess->next = NULL;

    if (head == NULL) {
        head = newProcess;
    } else {
        current = head;
        previous = NULL;

        while (current != NULL && current->priority <= priority) {
            previous = current;
            current = current->next;
        }

        if (previous == NULL) {
            newProcess->next = head;
            head = newProcess;
        } else {
            previous->next = newProcess;
            newProcess->next = current;
        }
    }
}

void KILL(char* name) {
    Process* current;
    Process* previous;

    current = head;
    previous = NULL;

    while (current != NULL) {
        if (strcmp(current->name, name) == 0) {
            if (previous == NULL) {
                head = current->next;
            } else {
                previous->next = current->next;
            }
            free(current);
            return;
        }
        previous = current;
        current = current->next;
    }

    printf("Process not found.\n");
}

void KILL_PRIORITY(int priority) {
    Process* current;
    Process* previous;
    Process* temp;

    current = head;
    previous = NULL;

    while (current != NULL) {
        if (current->priority == priority) {
            temp = current;
            if (previous == NULL) {
                head = current->next;
            } else {
                previous->next = current->next;
            }
            current = current->next;
            free(temp);
        } else {
            previous = current;
            current = current->next;
        }
    }
}

void LIST() {
    Process* current;

    current = head;

    while (current != NULL) {
        printf("%s %d\n", current->name, current->priority);
        current = current->next;
    }
}

void freeProcesses() {
    Process* current;
    Process* temp;

    current = head;

    while (current != NULL) {
        temp = current;
        current = current->next;
        free(temp);
    }

    head = NULL;
}
