import javax.swing.*;
import java.awt.*;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;

public class BasicCalculatorGUI extends JFrame {
    private JTextField firstNumberTextField;
    private JTextField secondNumberTextField;
    private JLabel resultLabel;

    public BasicCalculatorGUI() {
        setTitle("Basic Calculator");
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setSize(400, 300);
        setLayout(new GridLayout(5, 2, 10, 10));

        firstNumberTextField = new JTextField();
        secondNumberTextField = new JTextField();
        resultLabel = new JLabel("Result: ");

        JButton addButton = new JButton("Add");
        JButton subtractButton = new JButton("Subtract");
        JButton multiplyButton = new JButton("Multiply");
        JButton divideButton = new JButton("Divide");

        add(new JLabel("First Number:"));
        add(firstNumberTextField);
        add(new JLabel("Second Number:"));
        add(secondNumberTextField);
        add(addButton);
        add(subtractButton);
        add(multiplyButton);
        add(divideButton);
        add(resultLabel);

        addButton.addActionListener(new ActionListener() {
            @Override
            public void actionPerformed(ActionEvent e) {
                performOperation("add");
            }
        });

        subtractButton.addActionListener(new ActionListener() {
            @Override
            public void actionPerformed(ActionEvent e) {
                performOperation("subtract");
            }
        });

        multiplyButton.addActionListener(new ActionListener() {
            @Override
            public void actionPerformed(ActionEvent e) {
                performOperation("multiply");
            }
        });

        divideButton.addActionListener(new ActionListener() {
            @Override
            public void actionPerformed(ActionEvent e) {
                performOperation("divide");
            }
        });
    }

    private synchronized void performOperation(String operation) {
        try {
            double firstNumber = Double.parseDouble(firstNumberTextField.getText());
            double secondNumber = Double.parseDouble(secondNumberTextField.getText());
            double result = 0;

            switch (operation) {
                case "add":
                    result = add(firstNumber, secondNumber);
                    break;
                case "subtract":
                    result = subtract(firstNumber, secondNumber);
                    break;
                case "multiply":
                    result = multiply(firstNumber, secondNumber);
                    break;
                case "divide":
                    result = divide(firstNumber, secondNumber);
                    break;
            }

            resultLabel.setText("Result: " + result);
        } catch (NumberFormatException ex) {
            resultLabel.setText("Invalid input!");
        } catch (ArithmeticException ex) {
            resultLabel.setText("Cannot divide by zero!");
        }
    }

    private double add(double firstNumber, double secondNumber) {
        return firstNumber + secondNumber;
    }

    private double subtract(double firstNumber, double secondNumber) {
        return firstNumber - secondNumber;
    }

    private double multiply(double firstNumber, double secondNumber) {
        return firstNumber * secondNumber;
    }

    private double divide(double firstNumber, double secondNumber) {
        if (secondNumber == 0) {
            throw new ArithmeticException();
        }
        return firstNumber / secondNumber;
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(new Runnable() {
            @Override
            public void run() {
                new BasicCalculatorGUI().setVisible(true);
            }
        });
    }
}
