use std::collections::HashMap;

/// A struct to manage events in a community center.
/// Uses a HashMap to store event names as keys and their dates as values.
pub struct EventManager {
    events: HashMap<String, String>,
}

impl EventManager {
    /// Creates a new, empty EventManager.
    pub fn new() -> Self {
        EventManager {
            events: HashMap::new(),
        }
    }

    /// Adds a new event with the specified name and date.
    /// # Arguments
    /// * `name` - The name of the event.
    /// * `date` - The date of the event.
    pub fn add_event(&mut self, name: String, date: String) {
        self.events.insert(name, date);
    }

    /// Removes an event by its name.
    /// # Arguments
    /// * `name` - The name of the event to remove.
    /// # Returns
    /// Returns `Ok(())` if the event was removed successfully, or `Err(&'static str)` if the event does not exist.
    pub fn remove_event(&mut self, name: String) -> Result<(), &'static str> {
        if self.events.remove(&name).is_none() {
            Err("Event not found")
        } else {
            Ok(())
        }
    }

    /// Retrieves the date of an event by its name.
    /// # Arguments
    /// * `name` - The name of the event to retrieve.
    /// # Returns
    /// Returns `Some(date)` if the event exists, or `None` if it does not.
    pub fn get_event(&self, name: String) -> Option<String> {
        self.events.get(&name).cloned()
    }

    /// Returns a list of all event names currently registered.
    /// # Returns
    /// A `Vec<String>` containing all event names.
    pub fn list_events(&self) -> Vec<String> {
        self.events.keys().cloned().collect()
    }
}
