/**
 * Manages a to-do list with various operations.
 * @param {string} command - The operation to perform ('add', 'complete', 'delete', 'list').
 * @param {string|number} arg - The argument for the command (task description or task ID).
 * @returns {string|Array<Object>} - Result based on the command or an error message.
 */
function manageTodos(command, arg) {
    /** @type {Array<{task_id: number, description: string, completed: boolean}>} */
    const tasks = [];

    /**
     * Adds a new task with the given description.
     * @param {string} description - The task description.
     * @returns {string} - Confirmation message.
     */
    const addTask = function(description) {
        const newTask = {
            task_id: tasks.length + 1,
            description: description,
            completed: false
        };
        tasks.push(newTask);
        return `Task added with ID: ${newTask.task_id}`;
    };

    /**
     * Marks a task as completed.
     * @param {number} taskId - The ID of the task to complete.
     * @returns {string} - Confirmation or error message.
     */
    const completeTask = function(taskId) {
        const task = tasks.find(t => t.task_id === taskId);
        if (!task) {
            return `Error: Task with ID ${taskId} not found.`;
        }
        task.completed = true;
        return `Task ${taskId} marked as completed.`;
    };

    /**
     * Deletes a task.
     * @param {number} taskId - The ID of the task to delete.
     * @returns {string} - Confirmation or error message.
     */
    const deleteTask = function(taskId) {
        const index = tasks.findIndex(t => t.task_id === taskId);
        if (index === -1) {
            return `Error: Task with ID ${taskId} not found.`;
        }
        tasks.splice(index, 1);
        return `Task ${taskId} deleted.`;
    };

    /**
     * Lists all tasks.
     * @returns {Array<Object>} - Array of task objects.
     */
    const listTasks = function() {
        return tasks.map(task => ({
            task_id: task.task_id,
            description: task.description,
            completed: task.completed
        }));
    };

    switch (command) {
        case 'add':
            return addTask(arg);
        case 'complete':
            return completeTask(Number(arg));
        case 'delete':
            return deleteTask(Number(arg));
        case 'list':
            return listTasks();
        default:
            return `Error: Unknown command '${command}'.`;
    }
}
