    private static final String GREEN = "Green";
    private static final String RED = "Red";
    private static final String YELLOW = "Yellow";
    private static final int GREEN_DELAY = 30;
    private static final int RED_DELAY = 40;
    private static final int YELLOW_DELAY = 5;
    private static final String INITIAL_LIGHT = RED;

