        this.currentLight = INITIAL_LIGHT;
        this.currentDelay = RED_DELAY;
    }

    // Method to change the light to specified color
    public void changeLight(String color) {
        if (color.equals(GREEN) || color.equals(RED) || color.equals(YELLOW)) {
            this.currentLight = color;
            updateDelay();
        }
    }

    // Method to get current light color
    public String getCurrentLight() {
        return this.currentLight;
    }

    // Method to add delay for current light
    public void addDelay(int seconds) {
        this.currentDelay = seconds;
    }

    // Method to automatically switch to next light
    public void nextLight() {
        switch (this.currentLight) {
            case RED:
                this.currentLight = GREEN;
                break;
            case GREEN:
                this.currentLight = YELLOW;
                break;
            case YELLOW:
                this.currentLight = RED;
                break;
        }
        updateDelay();
    }

    // Private helper method to update delay based on current light
    private void updateDelay() {
        switch (this.currentLight) {
            case RED:
                this.currentDelay = RED_DELAY;
                break;
            case GREEN:
                this.currentDelay = GREEN_DELAY;
                break;
