#define MAX_SETTINGS 100
#define MAX_NAME_LENGTH 50
#define MAX_VALUE_LENGTH 100

typedef struct {
    char name[MAX_NAME_LENGTH];
    char value[MAX_VALUE_LENGTH];
    char defaultValue[MAX_VALUE_LENGTH];
} Setting;

Setting settings[MAX_SETTINGS];
int settingCount = 0;

void SET(char* setting_name, char* setting_value);
void GET(char* setting_name);
void RESET(char* setting_name);
void LIST_ALL();
int findSettingIndex(char* setting_name);

void SET(char* setting_name, char* setting_value) {
    int index = findSettingIndex(setting_name);
    if (index == -1) {
        if (settingCount >= MAX_SETTINGS) {
            printf("Error: Maximum number of settings reached.\n");
            return;
        }
        strcpy(settings[settingCount].name, setting_name);
        strcpy(settings[settingCount].value, setting_value);
        strcpy(settings[settingCount].defaultValue, "");
        settingCount++;
    } else {
        strcpy(settings[index].value, setting_value);
    }
}

void GET(char* setting_name) {
    int index = findSettingIndex(setting_name);
    if (index == -1) {
        printf("Error: Setting '%s' not found.\n", setting_name);
    } else {
        printf("%s\n", settings[index].value);
    }
}

void RESET(char* setting_name) {
    int index = findSettingIndex(setting_name);
    if (index == -1) {
        printf("Error: Setting '%s' not found.\n", setting_name);
    } else {
        if (strlen(settings[index].defaultValue) == 0) {
            printf("Error: No default value for setting '%s'.\n", setting_name);
        } else {
            strcpy(settings[index].value, settings[index].defaultValue);
        }
    }
}

void LIST_ALL() {
    for (int i = 0; i < settingCount; i++) {
        printf("%s: %s\n", settings[i].name, settings[i].value);
    }
}

int findSettingIndex(char* setting_name) {
    for (int i = 0; i < settingCount; i++) {
        if (strcmp(settings[i].name, setting_name) == 0) {
            return i;
        }
    }
    return -1;
}

int main() {
    char command[20];
    char setting_name[MAX_NAME_LENGTH];
    char setting_value[MAX_VALUE_LENGTH];

    while (1) {
        printf("> ");
        scanf("%s", command);

        if (strcmp(command, "SET") == 0) {
            scanf("%s %s", setting_name, setting_value);
            SET(setting_name, setting_value);
        } else if (strcmp(command, "GET") == 0) {
            scanf("%s", setting_name);
            GET(setting_name);
        } else if (strcmp(command, "RESET") == 0) {
            scanf("%s", setting_name);
            RESET(setting_name);
        } else if (strcmp(command, "LIST_ALL") == 0) {
            LIST_ALL();
        } else if (strcmp(command, "EXIT") == 0) {
            break;
        } else {
            printf("Error: Unknown command.\n");
        }
    }

    return 0;
