#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>

#define MAX_TASKS 100
#define MAX_NAME_LENGTH 50

typedef enum {
    WAITING,
    RUNNING,
    COMPLETED,
    CANCELLED
} TaskStatus;

typedef struct {
    char name[MAX_NAME_LENGTH];
    int duration;
    TaskStatus status;
} Task;

Task task_list[MAX_TASKS];
int task_count = 0;
pthread_mutex_t task_mutex = PTHREAD_MUTEX_INITIALIZER;

void ADD_TASK(char* task_name, int duration) {
    pthread_mutex_lock(&task_mutex);
    if (task_count >= MAX_TASKS) {
        printf("Error: Task list is full.\n");
        pthread_mutex_unlock(&task_mutex);
        return;
    }
    strcpy(task_list[task_count].name, task_name);
    task_list[task_count].duration = duration;
    task_list[task_count].status = WAITING;
    task_count++;
    pthread_mutex_unlock(&task_mutex);
}

void START_TASK(char* task_name) {
    pthread_mutex_lock(&task_mutex);
    int found = 0;
    for (int i = 0; i < task_count; i++) {
        if (strcmp(task_list[i].name, task_name) == 0) {
            found = 1;
            if (task_list[i].status == WAITING) {
                task_list[i].status = RUNNING;
                printf("Task '%s' started.\n", task_name);
            } else if (task_list[i].status == RUNNING) {
                printf("Error: Task '%s' is already running.\n", task_name);
            } else if (task_list[i].status == COMPLETED || task_list[i].status == CANCELLED) {
                printf("Error: Task '%s' cannot be started.\n", task_name);
            }
            break;
        }
    }
    if (!found) {
        printf("Error: Task '%s' not found.\n", task_name);
    }
    pthread_mutex_unlock(&task_mutex);
}

void CHECK_TASK(char* task_name) {
    pthread_mutex_lock(&task_mutex);
    int found = 0;
    for (int i = 0; i < task_count; i++) {
        if (strcmp(task_list[i].name, task_name) == 0) {
            found = 1;
            switch (task_list[i].status) {
                case WAITING:
                    printf("Task '%s' is waiting.\n", task_name);
                    break;
                case RUNNING:
                    printf("Task '%s' is running.\n", task_name);
                    break;
                case COMPLETED:
                    printf("Task '%s' is completed.\n", task_name);
                    break;
                case CANCELLED:
                    printf("Task '%s' is cancelled.\n", task_name);
                    break;
            }
            break;
        }
    }
    if (!found) {
        printf("Error: Task '%s' not found.\n", task_name);
    }
    pthread_mutex_unlock(&task_mutex);
}

void CANCEL_TASK(char* task_name) {
    pthread_mutex_lock(&task_mutex);
    int found = 0;
    for (int i = 0; i < task_count; i++) {
        if (strcmp(task_list[i].name, task_name) == 0) {
            found = 1;
            if (task_list[i].status == WAITING || task_list[i].status == RUNNING) {
                task_list[i].status = CANCELLED;
                printf("Task '%s' cancelled.\n", task_name);
            } else {
                printf("Error: Task '%s' cannot be cancelled.\n", task_name);
            }
            break;
        }
    }
    if (!found) {
        printf("Error: Task '%s' not found.\n", task_name);
    }
    pthread_mutex_unlock(&task_mutex);
}

int main() {
    // Example usage:
    // ADD_TASK("Task1", 10);
    // START_TASK("Task1");
    // CHECK_TASK("Task1");
    // CANCEL_TASK("Task1");
    return 0;
}
