class AppointmentSystem:
    def __init__(self):
        self.appointments: Dict[int, Tuple[str, str, int]] = {}
        self.next_id: int = 1

    def book_appointment(self, date: str, time: str, doctor_id: int) -> bool:
        for appointment_id, (existing_date, existing_time, existing_doctor_id) in self.appointments.items():
            if existing_date == date and existing_time == time and existing_doctor_id == doctor_id:
                return False
        self.appointments[self.next_id] = (date, time, doctor_id)
        self.next_id += 1
        return True

    def cancel_appointment(self, appointment_id: int) -> bool:
        if appointment_id in self.appointments:
            del self.appointments[appointment_id]
            return True
        return False

    def reschedule_appointment(self, appointment_id: int, new_date: str, new_time: str) -> bool:
        if appointment_id not in self.appointments:
            return False
        for existing_id, (existing_date, existing_time, existing_doctor_id) in self.appointments.items():
            if existing_id != appointment_id and existing_date == new_date and existing_time == new_time and existing_doctor_id == self.appointments[appointment_id][2]:
                return False
        old_data = self.appointments[appointment_id]
        self.appointments[appointment_id] = (new_date, new_time, old_data[2])
        return True

def schedule_appointment():
    return AppointmentSystem()
