fn add(num1: i32, num2: i32) -> i32 {
    num1 + num2
}

fn subtract(num1: i32, num2: i32) -> i32 {
    num1 - num2
}

fn multiply(num1: i32, num2: i32) -> i32 {
    num1 * num2
}

fn divide(num1: i32, num2: i32) -> Result<i32, String> {
    if num2 == 0 {
        Err(String::from("Error: Division by zero"))
    } else {
        Ok(num1 / num2)
    }
}

fn parse_input(input: &str) -> Option<(String, i32, i32)> {
    let parts: Vec<&str> = input.split_whitespace().collect();
    if parts.len() != 3 {
        return None;
    }
    let op = parts[0].to_uppercase();
    let num1 = i32::from_str(parts[1]).ok()?;
    let num2 = i32::from_str(parts[2]).ok()?;
    Some((op, num1, num2))
}

fn main() {
    loop {
        println!("Enter operation (ADD/SUBTRACT/MULTIPLY/DIVIDE) and two numbers, or 'exit' to quit:");
        let mut input = String::new();
        io::stdin().read_line(&mut input).expect("Failed to read input");
        let input = input.trim();
        if input.to_lowercase() == "exit" {
            break;
        }
        match parse_input(input) {
            Some((op, num1, num2)) => {
                match op.as_str() {
                    "ADD" => println!("Result: {}", add(num1, num2)),
                    "SUBTRACT" => println!("Result: {}", subtract(num1, num2)),
                    "MULTIPLY" => println!("Result: {}", multiply(num1, num2)),
                    "DIVIDE" => match divide(num1, num2) {
                        Ok(result) => println!("Result: {}", result),
                        Err(e) => println!("{}", e),
                    },
                    _ => println!("Invalid operation"),
                }
            }
            None => println!("Invalid input format. Expected: OPERATION NUM1 NUM2"),
        }
    }
