/**
 * Manages an in-memory shopping cart with basic operations.
 * @returns {Object} An object containing methods to manage the shopping cart.
 */
function manageShoppingCart() {
    let cart = {};

    /**
     * Adds a product with a specified quantity to the shopping cart.
     * @param {string} productId - The ID of the product to add.
     * @param {number} quantity - The quantity of the product to add.
     */
    function addProduct(productId, quantity) {
        let existingQuantity;
        if (cart[productId]) {
            existingQuantity = cart[productId];
            cart[productId] = existingQuantity + quantity;
        } else {
            cart[productId] = quantity;
        }
    }

    /**
     * Removes a product from the shopping cart.
     * @param {string} productId - The ID of the product to remove.
     * @returns {string} A message indicating success or error.
     */
    function removeProduct(productId) {
        let productExists;
        productExists = cart.hasOwnProperty(productId);
        if (productExists) {
            delete cart[productId];
            return 'Product removed successfully.';
        } else {
            return 'Error: Product not found in cart.';
        }
    }

    /**
     * Updates the quantity of a specific product in the shopping cart.
     * @param {string} productId - The ID of the product to update.
     * @param {number} quantity - The new quantity of the product.
     * @returns {string} A message indicating success or error.
     */
    function updateProduct(productId, quantity) {
        let productExists;
        productExists = cart.hasOwnProperty(productId);
        if (productExists) {
            cart[productId] = quantity;
            return 'Product quantity updated successfully.';
        } else {
            return 'Error: Product not found in cart.';
        }
    }

    /**
     * Retrieves the quantity of a product in the shopping cart.
     * @param {string} productId - The ID of the product to retrieve.
     * @returns {number|string} The quantity of the product or an error message.
     */
    function getProduct(productId) {
        let productExists;
        productExists = cart.hasOwnProperty(productId);
        if (productExists) {
            return cart[productId];
        } else {
            return 'Error: Product not found in cart.';
        }
    }

    return {
        addProduct,
        removeProduct,
        updateProduct,
        getProduct
    };
}
