```c
/* server.c */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <sys/sysinfo.h>

#define PORT 8080
#define BUFFER_SIZE 1024

void get_cpu_usage(char *buffer) {
    FILE *file = fopen("/proc/stat", "r");
    if (file == NULL) {
        sprintf(buffer, "Error reading CPU usage");
        return;
    }

    unsigned long long user, nice, system, idle, iowait, irq, softirq;
    fscanf(file, "cpu %llu %llu %llu %llu %llu %llu %llu", 
           &user, &nice, &system, &idle, &iowait, &irq, &softirq);
    fclose(file);

    unsigned long long total = user + nice + system + idle + iowait + irq + softirq;
    unsigned long long idle_total = idle + iowait;
    double usage = 100.0 * (1.0 - ((double)idle_total / (double)total));
    sprintf(buffer, "%.2f%%", usage);
}

void get_memory_usage(char *buffer) {
    struct sysinfo info;
    if (sysinfo(&info) != 0) {
        sprintf(buffer, "Error reading memory usage");
        return;
    }
    double usage = 100.0 * (1.0 - ((double)info.freeram / (double)info.totalram));
    sprintf(buffer, "%.2f%%", usage);
}

void get_disk_usage(char *buffer) {
    FILE *file = popen("df / | tail -1 | awk '{print $5}'", "r");
    if (file == NULL) {
        sprintf(buffer, "Error reading disk usage");
        return;
    }
    fgets(buffer, BUFFER_SIZE, file);
    pclose(file);
}

int main() {
    int server_fd, new_socket;
    struct sockaddr_in address;
    int opt = 1;
    int addrlen = sizeof(address);
    char buffer[BUFFER_SIZE] = {0};

    if ((server_fd = socket(AF_INET, SOCK_STREAM, 0)) == 0) {
        perror("socket failed");
        exit(EXIT_FAILURE);
    }

    if (setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR | SO_REUSEPORT, &opt, sizeof(opt))) {
        perror("setsockopt");
        exit(EXIT_FAILURE);
    }

    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY;
    address.sin_port = htons(PORT);

    if (bind(server_fd, (struct sockaddr *)&address, sizeof(address)) < 0) {
        perror("bind failed");
        exit(EXIT_FAILURE);
    }

    if (listen(server_fd, 3) < 0) {
        perror("listen");
        exit(EXIT_FAILURE);
    }

    while (1) {
        if ((new_socket = accept(server_fd, (struct sockaddr *)&address, (socklen_t*)&addrlen)) < 0) {
            perror("accept");
            exit(EXIT_FAILURE);
        }

        read(new_socket, buffer, BUFFER_SIZE);

        if (strcmp(buffer, "CPU_USAGE") == 0) {
            get_cpu_usage(buffer);
        } else if (strcmp(buffer, "MEMORY_USAGE") == 0) {
            get_memory_usage(buffer);
        } else if (strcmp(buffer, "DISK_USAGE") == 0) {
            get_disk_usage(buffer);
        } else {
            sprintf(buffer, "Invalid command");
        }

        send(new_socket, buffer, strlen(buffer), 0);
        close(new_socket);
    }

    return 0;
}
