use std::collections::HashMap;
use std::time::{SystemTime, UNIX_EPOCH};

struct SessionManager {
    sessions: HashMap<String, u64>,
}

impl SessionManager {
    pub fn new() -> Self {
        SessionManager {
            sessions: HashMap::new(),
        }
    }

    pub fn start_session(&mut self, user_id: String) {
        let start_time = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        self.sessions.insert(user_id, start_time);
    }

    pub fn check_session(&self, user_id: String, session_duration: u32) -> bool {
        match self.sessions.get(&user_id) {
            Some(&start_time) => {
                let current_time = SystemTime::now()
                    .duration_since(UNIX_EPOCH)
                    .unwrap()
                    .as_secs();
                let duration_passed = current_time - start_time;
                duration_passed < (session_duration as u64) * 60
            }
            None => false,
        }
    }

    pub fn end_session(&mut self, user_id: String) {
        self.sessions.remove(&user_id);
    }
}
