class Playlist {
private:
    std::vector<std::string> songs;
    std::mutex mtx;
    size_t currentSongIndex = 0;

public:
    void addSong(const std::string& songName) {
        std::lock_guard<std::mutex> lock(mtx);
        songs.push_back(songName);
        std::cout << "Added song: " << songName << std::endl;
    }

    void removeSong(const std::string& songName) {
        std::lock_guard<std::mutex> lock(mtx);
        auto it = std::find(songs.begin(), songs.end(), songName);
        if (it != songs.end()) {
            songs.erase(it);
            std::cout << "Removed song: " << songName << std::endl;
        } else {
            std::cout << "Error: Song '" << songName << "' not found in playlist." << std::endl;
        }
    }

    void play() {
        std::lock_guard<std::mutex> lock(mtx);
        if (songs.empty()) {
            std::cout << "Error: Playlist is empty." << std::endl;
            return;
        }
        if (currentSongIndex >= songs.size()) {
            currentSongIndex = 0;
        }
        std::cout << "Playing: " << songs[currentSongIndex] << std::endl;
        currentSongIndex++;
    }

    void list() {
        std::lock_guard<std::mutex> lock(mtx);
        if (songs.empty()) {
            std::cout << "Playlist is empty." << std::endl;
            return;
        }
        std::cout << "Playlist:" << std::endl;
        for (const auto& song : songs) {
            std::cout << "- " << song << std::endl;
        }
    }
};

int main() {
    Playlist playlist;
    std::string command;

    while (true) {
        std::cout << "Enter command (ADD, REMOVE, PLAY, LIST, or EXIT): ";
        std::getline(std::cin, command);

        if (command.substr(0, 3) == "ADD") {
            std::string songName = command.substr(4);
            playlist.addSong(songName);
        } else if (command.substr(0, 6) == "REMOVE") {
            std::string songName = command.substr(7);
            playlist.removeSong(songName);
        } else if (command == "PLAY") {
            playlist.play();
        } else if (command == "LIST") {
            playlist.list();
        } else if (command == "EXIT") {
            break;
        } else {
            std::cout << "Invalid command." << std::endl;
        }
    }

    return 0;
}
