        if (sscanf(input_line, "%19s %d %d", operation, &operand_x, &operand_y) == 3) {
            if (strcmp(operation, OPERATION_ADD) == 0) {
                printf("%d\n", operand_x + operand_y);
            } else if (strcmp(operation, OPERATION_SUBTRACT) == 0) {
                printf("%d\n", operand_x - operand_y);
            } else if (strcmp(operation, OPERATION_MULTIPLY) == 0) {
                printf("%d\n", operand_x * operand_y);
            } else if (strcmp(operation, OPERATION_DIVIDE) == 0) {
                if (operand_y == 0) {
