class SessionManager:
    def __init__(self) -> None:
        self.sessions: Dict[str, Dict[str, float]] = {}

    def create_session(self, user_id: str, expires_in: int) -> None:
        if user_id in self.sessions:
            raise ValueError(f"Session already exists for user: {user_id}")
        expiration_time: float = time.time() + expires_in
        self.sessions[user_id] = {"expiration_time": expiration_time}

    def get_session(self, user_id: str) -> Dict[str, float]:
        if user_id not in self.sessions:
            raise ValueError(f"No session found for user: {user_id}")
        session: Dict[str, float] = self.sessions[user_id]
        if session["expiration_time"] < time.time():
            del self.sessions[user_id]
            raise ValueError(f"Session expired for user: {user_id}")
        return session

    def delete_session(self, user_id: str) -> None:
        if user_id not in self.sessions:
            raise ValueError(f"No session found for user: {user_id}")
        del self.sessions[user_id]

    def extend_session(self, user_id: str, additional_time: int) -> None:
        if user_id not in self.sessions:
            raise ValueError(f"No session found for user: {user_id}")
        session: Dict[str, float] = self.sessions[user_id]
        if session["expiration_time"] < time.time():
            del self.sessions[user_id]
            raise ValueError(f"Session expired for user: {user_id}")
        session["expiration_time"] += additional_time
