use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::net::{TcpListener, TcpStream};
use std::io::{BufRead, BufReader, Write};
use std::thread;

type UserMap = Arc<Mutex<HashMap<String, TcpStream>>>;

fn handle_client(stream: TcpStream, users: UserMap) {
    let mut reader = BufReader::new(stream.try_clone().unwrap());
    let mut username = String::new();

    loop {
        let mut command = String::new();
        if reader.read_line(&mut command).is_err() {
            break;
        }
        let command = command.trim();

        if command.starts_with("JOIN ") {
            let new_username = command.trim_start_matches("JOIN ").to_string();
            username = new_username.clone();
            let mut users = users.lock().unwrap();
            users.insert(new_username.clone(), stream.try_clone().unwrap());
            broadcast(&users, &format!("{} has joined the chat.", new_username));
        } else if command == "LEAVE" {
            if !username.is_empty() {
                let mut users = users.lock().unwrap();
                users.remove(&username);
                broadcast(&users, &format!("{} has left the chat.", username));
            }
            break;
        } else if command.starts_with("MESSAGE ") {
            let message = command.trim_start_matches("MESSAGE ");
            let users = users.lock().unwrap();
            broadcast(&users, &format!("{}: {}", username, message));
        } else if command == "LIST" {
            let users = users.lock().unwrap();
            let user_list = users.keys().cloned().collect::<Vec<_>>().join(", ");
            let _ = writeln!(stream, "Connected users: {}", user_list);
        }
    }
}

fn broadcast(users: &HashMap<String, TcpStream>, message: &str) {
    for (_, mut stream) in users.iter() {
        let _ = writeln!(stream, "{}", message);
    }
}

fn main() {
    let listener = TcpListener::bind("127.0.0.1:8080").unwrap();
    let users: UserMap = Arc::new(Mutex::new(HashMap::new()));

    for stream in listener.incoming() {
        let stream = stream.unwrap();
        let users = Arc::clone(&users);

        thread::spawn(move || {
            handle_client(stream, users);
        });
    }
}
