#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct {
    int customerId;
    double balance;
} Account;

Account* accounts = NULL;
int accountCount = 0;

void createAccount(int customerId, double initialBalance) {
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            printf("Error: Customer ID %d already exists.\n", customerId);
            return;
        }
    }

    accounts = realloc(accounts, (accountCount + 1) * sizeof(Account));
    if (accounts == NULL) {
        printf("Error: Memory allocation failed.\n");
        return;
    }

    accounts[accountCount].customerId = customerId;
    accounts[accountCount].balance = initialBalance;
    accountCount++;
    printf("Account created successfully for Customer ID %d.\n", customerId);
}

void deposit(int customerId, double amount) {
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            if (amount <= 0) {
                printf("Error: Deposit amount must be positive.\n");
                return;
            }
            accounts[i].balance += amount;
            printf("Deposit successful. New balance: %.2f\n", accounts[i].balance);
            return;
        }
    }
    printf("Error: Customer ID %d not found.\n", customerId);
}

void withdraw(int customerId, double amount) {
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            if (amount <= 0) {
                printf("Error: Withdrawal amount must be positive.\n");
                return;
            }
            if (accounts[i].balance < amount) {
                printf("Error: Insufficient balance.\n");
                return;
            }
            accounts[i].balance -= amount;
            printf("Withdrawal successful. New balance: %.2f\n", accounts[i].balance);
            return;
        }
    }
    printf("Error: Customer ID %d not found.\n", customerId);
}

double getBalance(int customerId) {
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            return accounts[i].balance;
        }
    }
    printf("Error: Customer ID %d not found.\n", customerId);
    return -1.0;
}

void closeAccount(int customerId) {
    for (int i = 0; i < accountCount; i++) {
        if (accounts[i].customerId == customerId) {
            for (int j = i; j < accountCount - 1; j++) {
                accounts[j] = accounts[j + 1];
            }
            accounts = realloc(accounts, (accountCount - 1) * sizeof(Account));
            accountCount--;
            printf("Account closed successfully for Customer ID %d.\n", customerId);
            return;
        }
    }
    printf("Error: Customer ID %d not found.\n", customerId);
}

int main() {
    // Example usage
    createAccount(1, 100.0);
    deposit(1, 50.0);
    withdraw(1, 30.0);
    printf("Balance: %.2f\n", getBalance(1));
    closeAccount(1);
    return 0;
}
