        if voter_id not in self.registered_voters:
            return f"Error: Voter {voter_id} is not registered."
        self.votes[candidate_name] = self.votes.get(candidate_name, 0) + 1
        return f"Vote for {candidate_name} by {voter_id} recorded successfully."

    def results(self) -> Dict[str, int]:
