impl AttendanceSystem {
    fn new() -> Self {
        AttendanceSystem {
            students: HashMap::new(),
        }
    }

    fn add_student(&mut self, name: &str) -> Result<(), String> {
        if self.students.len() >= MAX_STUDENTS {
            return Err("Maximum number of students reached".to_string());
        }
        if self.students.contains_key(name) {
            return Err("Student already exists".to_string());
        }
        self.students.insert(name.to_string(), false);
        Ok(())
    }

    fn remove_student(&mut self, name: &str) -> Result<(), String> {
        if !self.students.contains_key(name) {
            return Err("Student does not exist".to_string());
        }
        self.students.remove(name);
        Ok(())
    }

    fn check_in(&mut self, name: &str) -> Result<(), String> {
        if let Some(present) = self.students.get_mut(name) {
            *present = true;
            Ok(())
        } else {
            Err("Student does not exist".to_string())
        }
    }

    fn report(&self) {
        println!("Attendance Report:");
        for (name, present) in &self.students {
            println!("{}: {}", name, if *present { "Present" } else { "Absent" });
        }
    }
}

fn main() {
    let mut system = AttendanceSystem::new();

    loop {
        println!("Enter command (ADD, REMOVE, CHECK_IN, REPORT, or EXIT):");
        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();
        let parts: Vec<&str> = input.trim().split_whitespace().collect();

        match parts.as_slice() {
            ["ADD", name] => match system.add_student(name) {
                Ok(_) => println!("Student added successfully"),
                Err(e) => println!("Error: {}", e),
            },
            ["REMOVE", name] => match system.remove_student(name) {
                Ok(_) => println!("Student removed successfully"),
                Err(e) => println!("Error: {}", e),
            },
            ["CHECK_IN", name] => match system.check_in(name) {
                Ok(_) => println!("Student checked in successfully"),
                Err(e) => println!("Error: {}", e),
            },
            ["REPORT"] => system.report(),
            ["EXIT"] => break,
            _ => println!("Invalid command"),
        }
    }
}
