#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_TASKS 100

typedef struct {
    int task_id;
    int priority;
} Task;

Task task_queue[MAX_TASKS];
int task_count = 0;

bool is_task_id_unique(int task_id) {
    for (int i = 0; i < task_count; i++) {
        if (task_queue[i].task_id == task_id) {
            return false;
        }
    }
    return true;
}

int find_task_index(int task_id) {
    for (int i = 0; i < task_count; i++) {
        if (task_queue[i].task_id == task_id) {
            return i;
        }
    }
    return -1;
}

void add_task(int task_id, int priority) {
    if (task_count >= MAX_TASKS) {
        printf("Error: Task queue is full.\n");
        return;
    }
    if (!is_task_id_unique(task_id)) {
        printf("Error: Task ID %d already exists.\n", task_id);
        return;
    }
    task_queue[task_count].task_id = task_id;
    task_queue[task_count].priority = priority;
    task_count++;
    printf("Task %d with priority %d added successfully.\n", task_id, priority);
}

void remove_task(int task_id) {
    int index = find_task_index(task_id);
    if (index == -1) {
        printf("Error: Task ID %d does not exist.\n", task_id);
        return;
    }
    for (int i = index; i < task_count - 1; i++) {
        task_queue[i] = task_queue[i + 1];
    }
    task_count--;
    printf("Task %d removed successfully.\n", task_id);
}

void change_priority(int task_id, int new_priority) {
    int index = find_task_index(task_id);
    if (index == -1) {
        printf("Error: Task ID %d does not exist.\n", task_id);
        return;
    }
    task_queue[index].priority = new_priority;
    printf("Task %d priority changed to %d successfully.\n", task_id, new_priority);
}

void fetch_next_task() {
    if (task_count == 0) {
        printf("Error: No tasks in the queue.\n");
        return;
    }
    int highest_priority_index = 0;
    for (int i = 1; i < task_count; i++) {
        if (task_queue[i].priority > task_queue[highest_priority_index].priority) {
            highest_priority_index = i;
        }
    }
    Task next_task = task_queue[highest_priority_index];
    remove_task(next_task.task_id);
    printf("Fetched task: ID %d, Priority %d\n", next_task.task_id, next_task.priority);
}

int main() {
    // Example usage
    add_task(1, 3);
    add_task(2, 5);
    add_task(3, 1);
    fetch_next_task();
    change_priority(3, 6);
    fetch_next_task();
    remove_task(1);
    fetch_next_task();
    return 0;
}
