function calculateTimeSpan(startTimeStamp, endTimeStamp) {
    const secondsPerMinute = 60;
    const minutesPerHour = 60;
    const hoursPerDay = 24;
    const millisecondsPerSecond = 1000;
    const millisecondsPerMinute = secondsPerMinute * millisecondsPerSecond;
    const millisecondsPerHour = minutesPerHour * millisecondsPerMinute;
    const millisecondsPerDay = hoursPerDay * millisecondsPerHour;

    let startDate;
    let endDate;
    let timeDiff;
    let years;
    let months;
    let days;
    let hours;
    let minutes;
    let seconds;

    if (isNaN(startTimeStamp) || isNaN(endTimeStamp)) {
        throw new Error('Invalid timestamp(s): One or both timestamps are not valid numbers.');
    }

    startDate = new Date(startTimeStamp);
    endDate = new Date(endTimeStamp);

    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
        throw new Error('Invalid timestamp(s): One or both timestamps could not be converted to a valid Date.');
    }

    if (endDate < startDate) {
        throw new Error('Invalid time range: endTimeStamp must be later than or equal to startTimeStamp.');
    }

    timeDiff = endDate - startDate;

    seconds = Math.floor(timeDiff / millisecondsPerSecond) % secondsPerMinute;
    minutes = Math.floor(timeDiff / millisecondsPerMinute) % minutesPerHour;
    hours = Math.floor(timeDiff / millisecondsPerHour) % hoursPerDay;
    days = Math.floor(timeDiff / millisecondsPerDay);

    // Approximate calculations for years and months
    years = endDate.getFullYear() - startDate.getFullYear();
    months = endDate.getMonth() - startDate.getMonth();
    if (months < 0) {
        years--;
        months += 12;
    }
    if (endDate.getDate() < startDate.getDate()) {
        months--;
    }

    return {
        years,
        months,
        days,
        hours,
        minutes,
        seconds
    };
}
