#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

class Flight {
public:
    Flight(const std::string& id) : flightID(id) {}

    void bookPassenger(const std::string& passengerName) {
        passengers.push_back(passengerName);
    }

    void cancelPassenger(const std::string& passengerName) {
        auto it = std::find(passengers.begin(), passengers.end(), passengerName);
        if (it != passengers.end()) {
            passengers.erase(it);
        }
    }

    const std::vector<std::string>& getPassengers() const {
        return passengers;
    }

    const std::string& getFlightID() const {
        return flightID;
    }

protected:
    std::string flightID;

private:
    std::vector<std::string> passengers;
};

class ReservationSystem {
public:
    void bookFlight(const std::string& flightID, const std::string& passengerName) {
        flights[flightID].bookPassenger(passengerName);
        std::cout << "Booked passenger " << passengerName << " on flight " << flightID << std::endl;
    }

    void cancelFlight(const std::string& flightID, const std::string& passengerName) {
        auto it = flights.find(flightID);
        if (it != flights.end()) {
            it->second.cancelPassenger(passengerName);
            std::cout << "Canceled booking for passenger " << passengerName << " on flight " << flightID << std::endl;
        } else {
            std::cout << "Flight " << flightID << " not found." << std::endl;
        }
    }

    void displayFlightList() const {
        std::cout << "Flight List:" << std::endl;
        for (const auto& pair : flights) {
            std::cout << "Flight " << pair.first << ": " << pair.second.getPassengers().size() << " passengers" << std::endl;
        }
    }

    void displayPassengerList(const std::string& flightID) const {
        auto it = flights.find(flightID);
        if (it != flights.end()) {
            std::cout << "Passengers on Flight " << flightID << ":" << std::endl;
            for (const auto& passenger : it->second.getPassengers()) {
                std::cout << passenger << std::endl;
            }
        } else {
            std::cout << "Flight " << flightID << " not found." << std::endl;
        }
    }

protected:
    std::map<std::string, Flight> flights;
};

int main() {
    ReservationSystem system;
    std::string command;

    while (true) {
        std::cout << "> ";
        std::getline(std::cin, command);

        if (command == "FLIGHT_LIST") {
            system.displayFlightList();
        } else if (command.substr(0, 4) == "BOOK") {
            size_t space1 = command.find(' ', 5);
            std::string flightID = command.substr(5, space1 - 5);
            std::string passengerName = command.substr(space1 + 1);
            system.bookFlight(flightID, passengerName);
        } else if (command.substr(0, 6) == "CANCEL") {
            size_t space1 = command.find(' ', 7);
            std::string flightID = command.substr(7, space1 - 7);
            std::string passengerName = command.substr(space1 + 1);
            system.cancelFlight(flightID, passengerName);
        } else if (command.substr(0, 14) == "PASSENGER_LIST") {
            std::string flightID = command.substr(15);
            system.displayPassengerList(flightID);
        } else {
            std::cout << "Invalid command." << std::endl;
        }
    }

    return 0;
}
