from typing import List, Dict, Union
import statistics
import math

def compute_volatility(price_data: List[float]) -> float:
    """
    Computes the volatility of the provided list of price data points.

    Args:
        price_data: List of price data points.

    Returns:
        Volatility as a float.
    """
    if not price_data:
        raise ValueError("Price data list is empty.")

    if len(price_data) < 2:
        raise ValueError("Price data must contain at least two points.")

    if not all(isinstance(price, (int, float)) for price in price_data):
        raise ValueError("Price data must contain only numeric values.")

    returns = []
    for i in range(1, len(price_data)):
        daily_return = (price_data[i] - price_data[i-1]) / price_data[i-1]
        returns.append(daily_return)

    volatility = statistics.stdev(returns) * math.sqrt(252)  # Annualized volatility
    return volatility

def evaluate_risk(profile: Dict[str, Union[str, int, float]], financial_products: List[Dict[str, Union[str, float]]]) -> str:
    """
    Assesses the risk level based on a portfolio profile and a list of financial products.

    Args:
        profile: Dictionary containing investor profile (e.g., risk tolerance, age).
        financial_products: List of dictionaries representing financial products (e.g., name, volatility).

    Returns:
        Risk level as a string (e.g., "Low", "Medium", "High").
    """
    if not profile:
        raise ValueError("Profile dictionary is empty.")

    if not financial_products:
        raise ValueError("Financial products list is empty.")

    required_profile_keys = ["risk_tolerance", "age"]
    for key in required_profile_keys:
        if key not in profile:
            raise ValueError(f"Profile missing required key: {key}")

    if not isinstance(profile["risk_tolerance"], (int, float)) or not isinstance(profile["age"], int):
        raise ValueError("Profile values must be numeric.")

    if profile["risk_tolerance"] < 0 or profile["age"] < 0:
        raise ValueError("Profile values cannot be negative.")

    required_product_keys = ["name", "volatility"]
    for product in financial_products:
        for key in required_product_keys:
            if key not in product:
                raise ValueError(f"Financial product missing required key: {key}")

        if not isinstance(product["volatility"], (int, float)):
            raise ValueError("Product volatility must be numeric.")

        if product["volatility"] < 0:
            raise ValueError("Product volatility cannot be negative.")

    total_volatility = sum(product["volatility"] for product in financial_products) / len(financial_products)
    risk_score = (profile["risk_tolerance"] * 0.6) + (total_volatility * 0.4)

    if risk_score < 3:
        return "Low"
    elif 3 <= risk_score < 7:
        return "Medium"
    else:
        return "High"
