@RestController
@RequestMapping("/profiles")
public class ProfileController {
    private final Map<String, UserProfile> profiles = new HashMap<>();

    @PostMapping
    public ResponseEntity<String> createProfile(@RequestBody UserProfile userProfile) {
        if (profiles.containsKey(userProfile.getUsername())) {
            return ResponseEntity.status(HttpStatus.CONFLICT).body("Profile already exists");
        }
        profiles.put(userProfile.getUsername(), userProfile);
        return ResponseEntity.status(HttpStatus.CREATED).body("Profile created successfully");
    }

    @GetMapping("/profile/{username}")
    public ResponseEntity<UserProfile> getProfile(@PathVariable String username) {
        UserProfile profile = profiles.get(username);
        if (profile == null) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).body(null);
        }
        return ResponseEntity.ok(profile);
    }

    @PutMapping("/profile/{username}")
    public ResponseEntity<String> updateProfile(
            @PathVariable String username,
            @RequestBody UserProfile updatedProfile) {
        if (!profiles.containsKey(username)) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).body("Profile not found");
        }
        UserProfile existingProfile = profiles.get(username);
        existingProfile.setEmail(updatedProfile.getEmail());
        existingProfile.setAge(updatedProfile.getAge());
        profiles.put(username, existingProfile);
        return ResponseEntity.ok("Profile updated successfully");
    }

    @DeleteMapping("/profile/{username}")
    public ResponseEntity<String> deleteProfile(@PathVariable String username) {
        if (!profiles.containsKey(username)) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).body("Profile not found");
        }
        profiles.remove(username);
        return ResponseEntity.status(HttpStatus.NO_CONTENT).body(null);
    }

    public static class UserProfile {
        private String username;
        private String email;
        private int age;

        public String getUsername() {
            return username;
        }

        public void setUsername(String username) {
            this.username = username;
        }

        public String getEmail() {
            return email;
        }

        public void setEmail(String email) {
            this.email = email;
        }

        public int getAge() {
            return age;
        }

        public void setAge(int age) {
            this.age = age;
        }
    }
}
