#include <iostream>

class Stack {
private:
    struct Node {
        int data;
        Node* next;
        Node(int val) : data(val), next(nullptr) {}
    };
    Node* top;
    int stackSize;

public:
    Stack() : top(nullptr), stackSize(0) {}

    void push(int value) {
        Node* newNode = new Node(value);
        newNode->next = top;
        top = newNode;
        stackSize++;
    }

    int pop() {
        if (isEmpty()) {
            std::cerr << "Stack underflow\n";
            return -1;
        }
        Node* temp = top;
        int poppedValue = temp->data;
        top = top->next;
        delete temp;
        stackSize--;
        return poppedValue;
    }

    int peek() {
        if (isEmpty()) {
            std::cerr << "Stack is empty\n";
            return -1;
        }
        return top->data;
    }

    int size() {
        return stackSize;
    }

    bool isEmpty() {
        return top == nullptr;
    }
};
