function createTokenBucketRateLimiter() {
    const maxCallsPerMinute = 100;
    const timeIntervalInMilliseconds = 60000;
    let tokensAvailable = maxCallsPerMinute;
    let lastRefillTime = Date.now();

    function refillTokens() {
        const currentTime = Date.now();
        const timeElapsed = currentTime - lastRefillTime;
        const tokensToAdd = Math.floor(timeElapsed / (timeIntervalInMilliseconds / maxCallsPerMinute));

        if (tokensToAdd > 0) {
            tokensAvailable = Math.min(tokensAvailable + tokensToAdd, maxCallsPerMinute);
            lastRefillTime = currentTime;
        }
    }

    return function isRequestAllowed() {
        refillTokens();

        if (tokensAvailable > 0) {
            tokensAvailable--;
            return true;
        }

        return false;
    };
}
